function addTodo(title: string): void {
  const trimmed = title.trim()
  if (!trimmed) {
    return
  }
  const todo: TodoUI = {
    id: nanoid(),
    title: trimmed,
    completed: false,
    createdAt: Date.now(),
    completedAt: null,
  }
  todos.value = [...todos.value, todo]
}

